const zeldaQuestions = [
  {t:"m",q:"\u00bfCu\u00e1l es el nombre de la princesa central de la saga The Legend of Zelda?",o:["Peach", "Zelda", "Midna", "Malon"],a:1,exp:"La princesa Zelda es una de las figuras centrales de la saga y suele estar vinculada al destino de Hyrule.",extra:"Aunque muchas veces Link es el personaje jugable principal, Zelda suele representar sabidur\u00eda, linaje real y poder sagrado."},
  {t:"m",q:"\u00bfCu\u00e1l es el nombre del h\u00e9roe que suele protagonizar la saga?",o:["Link", "Rauru", "Ganondorf", "Tingle"],a:0,exp:"Link es el h\u00e9roe principal de la mayor\u00eda de juegos de The Legend of Zelda.",extra:"Link no siempre es exactamente la misma persona: la saga juega con reencarnaciones, eras distintas y m\u00faltiples h\u00e9roes unidos por el esp\u00edritu del valor."},
  {t:"m",q:"\u00bfCu\u00e1l es el reino donde transcurren muchas aventuras de Zelda?",o:["Mushroom Kingdom", "Hyrule", "Spira", "Midgar"],a:1,exp:"Hyrule es el reino principal y escenario m\u00e1s recurrente de la saga.",extra:"Hyrule cambia de forma entre juegos, pero suele incluir lugares ic\u00f3nicos como el Castillo de Hyrule, el Lago Hylia, la Monta\u00f1a de la Muerte y el Bosque Perdido."},
  {t:"m",q:"\u00bfQu\u00e9 reliquia sagrada est\u00e1 formada por Poder, Sabidur\u00eda y Valor?",o:["La Master Sword", "La Trifuerza", "La Ocarina del Tiempo", "El Escudo Hyliano"],a:1,exp:"La Trifuerza est\u00e1 formada por tres partes: Poder, Sabidur\u00eda y Valor.",extra:"Cada fragmento suele asociarse con Ganondorf, Zelda y Link respectivamente, creando una estructura m\u00edtica que atraviesa gran parte de la saga."},
  {t:"m",q:"\u00bfQu\u00e9 villano suele estar asociado a la Trifuerza del Poder?",o:["Vaati", "Ganondorf", "Zant", "Ghirahim"],a:1,exp:"Ganondorf suele portar o buscar la Trifuerza del Poder.",extra:"Ganondorf es una de las grandes amenazas recurrentes de Hyrule. Su forma demon\u00edaca, Ganon, representa una fuerza de destrucci\u00f3n casi eterna."},
  {t:"m",q:"\u00bfCu\u00e1l es la espada legendaria m\u00e1s famosa de la saga?",o:["Biggoron Sword", "Master Sword", "Four Sword", "Kokiri Sword"],a:1,exp:"La Master Sword es la espada legendaria destinada a repeler el mal.",extra:"Tambi\u00e9n llamada Espada Maestra, aparece en muchos juegos como arma sagrada capaz de enfrentar a Ganon y otras fuerzas oscuras."},
  {t:"m",q:"\u00bfQu\u00e9 escudo es uno de los m\u00e1s ic\u00f3nicos de Link?",o:["Escudo Hyliano", "Escudo Deku", "Escudo Espejo", "Escudo Gerudo"],a:0,exp:"El Escudo Hyliano es el escudo m\u00e1s reconocible de Link en muchas entregas.",extra:"Su dise\u00f1o azul con el emblema de Hyrule y la Trifuerza se volvi\u00f3 una de las im\u00e1genes m\u00e1s famosas de Nintendo."},
  {t:"m",q:"\u00bfQu\u00e9 instrumento es central en Ocarina of Time?",o:["Flauta de Pan", "Ocarina del Tiempo", "Arpa de la Diosa", "Batuta de los Vientos"],a:1,exp:"La Ocarina del Tiempo permite tocar melod\u00edas m\u00e1gicas y manipular elementos del mundo.",extra:"En Ocarina of Time, la m\u00fasica no es solo decoraci\u00f3n: sirve para viajar, abrir caminos, cambiar el tiempo y conectar personajes."},
  {t:"m",q:"\u00bfQu\u00e9 juego introdujo de forma famosa el viaje entre Link ni\u00f1o y Link adulto?",o:["A Link to the Past", "Ocarina of Time", "The Wind Waker", "Skyward Sword"],a:1,exp:"Ocarina of Time permite alternar entre dos etapas temporales clave de Link.",extra:"Ese salto temporal marc\u00f3 profundamente la narrativa de Zelda y es una de las razones por las que el juego es considerado hist\u00f3rico."},
  {t:"m",q:"\u00bfQu\u00e9 hada acompa\u00f1a a Link en Ocarina of Time?",o:["Tatl", "Navi", "Ciela", "Fi"],a:1,exp:"Navi es el hada que acompa\u00f1a a Link en Ocarina of Time.",extra:"Su famosa frase \u201cHey! Listen!\u201d se volvi\u00f3 uno de los sonidos m\u00e1s recordados de la saga, querida y burlada por fans en igual medida."},
  {t:"m",q:"\u00bfCu\u00e1l es el \u00e1rbol protector del Bosque Kokiri en Ocarina of Time?",o:["\u00c1rbol Deku", "\u00c1rbol Maku", "Gran \u00c1rbol Mojo", "\u00c1rbol Minish"],a:0,exp:"El Gran \u00c1rbol Deku protege a los Kokiri y gu\u00eda a Link al inicio de Ocarina of Time.",extra:"Su muerte temprana le da a la aventura un tono de destino inevitable: Link debe abandonar el bosque y entrar en un mundo mucho m\u00e1s grande."},
  {t:"m",q:"\u00bfQu\u00e9 raza vive tradicionalmente en la Monta\u00f1a de la Muerte?",o:["Zora", "Goron", "Kokiri", "Rito"],a:1,exp:"Los Goron viven en zonas monta\u00f1osas y volc\u00e1nicas como la Monta\u00f1a de la Muerte.",extra:"Los Goron son fuertes, rocosos y suelen tener una cultura amistosa basada en miner\u00eda, comida de rocas y hermandad."},
  {t:"m",q:"\u00bfQu\u00e9 raza acu\u00e1tica aparece frecuentemente en la saga?",o:["Zora", "Gerudo", "Sheikah", "Korok"],a:0,exp:"Los Zora son una raza acu\u00e1tica asociada a r\u00edos, lagos y dominios submarinos.",extra:"Su dise\u00f1o cambia mucho seg\u00fan el juego: pueden aparecer como aliados elegantes o como enemigos monstruosos en entregas m\u00e1s antiguas."},
  {t:"m",q:"\u00bfQu\u00e9 pueblo del desierto est\u00e1 compuesto tradicionalmente casi solo por mujeres?",o:["Kokiri", "Gerudo", "Rito", "Twili"],a:1,exp:"Las Gerudo son una tribu del desierto formada casi exclusivamente por mujeres.",extra:"Ganondorf nace como var\u00f3n Gerudo en varias versiones del lore, algo que lo conecta directamente con su pueblo y con la historia de Hyrule."},
  {t:"m",q:"\u00bfQu\u00e9 personaje usa la identidad de Sheik en Ocarina of Time?",o:["Impa", "Zelda", "Malon", "Nabooru"],a:1,exp:"Zelda se disfraza como Sheik para ocultarse de Ganondorf y ayudar a Link.",extra:"La revelaci\u00f3n de Sheik como Zelda es uno de los momentos m\u00e1s recordados de Ocarina of Time."},
  {t:"m",q:"\u00bfQui\u00e9n es la protectora Sheikah de Zelda en varios juegos?",o:["Impa", "Urbosa", "Riju", "Purah"],a:0,exp:"Impa es una figura Sheikah recurrente y suele servir como guardiana o consejera de Zelda.",extra:"Impa cambia mucho entre entregas: puede ser anciana sabia, guerrera atl\u00e9tica o l\u00edder de una aldea, pero casi siempre est\u00e1 ligada al deber de proteger Hyrule."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Zelda usa una m\u00e1scara como elemento central y tiene un ciclo de tres d\u00edas?",o:["Majora\u2019s Mask", "Twilight Princess", "Phantom Hourglass", "Oracle of Ages"],a:0,exp:"Majora\u2019s Mask gira alrededor de m\u00e1scaras m\u00e1gicas y un ciclo temporal de tres d\u00edas.",extra:"Es uno de los juegos m\u00e1s oscuros y extra\u00f1os de la saga, con temas de p\u00e9rdida, duelo, repetici\u00f3n y salvaci\u00f3n imposible de todos a la vez."},
  {t:"m",q:"\u00bfQu\u00e9 luna amenaza con caer sobre Termina?",o:["La Luna Carmes\u00ed", "La luna de Majora\u2019s Mask", "La Luna del Crep\u00fasculo", "La Luna Plateada"],a:1,exp:"En Majora\u2019s Mask, una luna con rostro amenazante cae lentamente sobre Termina.",extra:"El reloj constante y la imagen de la luna acerc\u00e1ndose crean una tensi\u00f3n \u00fanica dentro de la saga."},
  {t:"m",q:"\u00bfQu\u00e9 personaje roba la M\u00e1scara de Majora al inicio del juego?",o:["Skull Kid", "Ghirahim", "Vaati", "Zant"],a:0,exp:"Skull Kid roba la M\u00e1scara de Majora y queda influenciado por su poder.",extra:"Skull Kid no es simplemente malvado: su historia tiene tristeza, abandono y manipulaci\u00f3n por una fuerza mucho m\u00e1s oscura."},
  {t:"m",q:"\u00bfQu\u00e9 hada acompa\u00f1a a Link en Majora\u2019s Mask?",o:["Navi", "Tatl", "Fi", "Proxi"],a:1,exp:"Tatl acompa\u00f1a a Link durante Majora\u2019s Mask.",extra:"A diferencia de Navi, Tatl tiene una personalidad m\u00e1s brusca al principio, pero su relaci\u00f3n con Link evoluciona durante la aventura."},
  {t:"m",q:"\u00bfQu\u00e9 m\u00e1scara permite a Link transformarse en Deku en Majora\u2019s Mask?",o:["M\u00e1scara Deku", "M\u00e1scara Goron", "M\u00e1scara Zora", "M\u00e1scara de la Fiera Deidad"],a:0,exp:"La M\u00e1scara Deku transforma a Link en un Deku Scrub.",extra:"Las transformaciones de Majora\u2019s Mask no son simples disfraces: suelen estar ligadas a almas, tragedias y poderes de personajes ca\u00eddos."},
  {t:"m",q:"\u00bfQu\u00e9 m\u00e1scara transforma a Link en Goron?",o:["M\u00e1scara de Darmani", "M\u00e1scara Zora", "M\u00e1scara Keaton", "M\u00e1scara Bremen"],a:0,exp:"La M\u00e1scara Goron contiene el esp\u00edritu de Darmani y permite a Link tomar forma Goron.",extra:"Con esta forma, Link puede rodar a gran velocidad, resistir lava y usar fuerza f\u00edsica superior."},
  {t:"m",q:"\u00bfQu\u00e9 m\u00e1scara transforma a Link en Zora?",o:["M\u00e1scara de Mikau", "M\u00e1scara de Kamaro", "M\u00e1scara de Gibdo", "M\u00e1scara de Piedra"],a:0,exp:"La M\u00e1scara Zora permite a Link transformarse en Mikau, guitarrista Zora.",extra:"Esta transformaci\u00f3n permite nadar con gran velocidad y luchar usando aletas como bumeranes."},
  {t:"m",q:"\u00bfQu\u00e9 juego presenta un Hyrule inundado y viajes en barco?",o:["The Wind Waker", "Twilight Princess", "Skyward Sword", "The Minish Cap"],a:0,exp:"The Wind Waker transcurre en un gran mar que cubre el antiguo Hyrule.",extra:"Su estilo visual cel-shading fue pol\u00e9mico al principio, pero con el tiempo se convirti\u00f3 en uno de los apartados art\u00edsticos m\u00e1s queridos de la saga."},
  {t:"m",q:"\u00bfC\u00f3mo se llama el barco parlante de The Wind Waker?",o:["Rey de los Leones Rojos", "Esp\u00edritu del Oc\u00e9ano", "Mascar\u00f3n del Viento", "Barco Deku"],a:0,exp:"El Rey de los Leones Rojos gu\u00eda a Link por el Gran Mar en The Wind Waker.",extra:"Su identidad verdadera conecta directamente la aventura mar\u00edtima con la historia perdida de Hyrule."},
  {t:"m",q:"\u00bfQu\u00e9 objeto dirige los vientos en The Wind Waker?",o:["Ocarina del Tiempo", "Batuta de los Vientos", "Arpa de la Diosa", "Flauta Espiritual"],a:1,exp:"La Batuta de los Vientos permite a Link controlar la direcci\u00f3n del viento y tocar melod\u00edas m\u00e1gicas.",extra:"El control del viento es esencial para navegar, resolver puzzles y avanzar por las islas del Gran Mar."},
  {t:"m",q:"\u00bfQu\u00e9 hermana de Link es secuestrada al inicio de The Wind Waker?",o:["Aryll", "Tetra", "Medli", "Ilia"],a:0,exp:"Aryll, la hermana de Link, es secuestrada por un ave gigante al inicio del juego.",extra:"Su secuestro motiva a Link a abandonar Isla Initia y comenzar una aventura mucho m\u00e1s grande de lo esperado."},
  {t:"m",q:"\u00bfQui\u00e9n es Tetra en The Wind Waker?",o:["Una pirata que resulta ser Zelda", "Una sacerdotisa Zora", "Una Gerudo exiliada", "Una hada del viento"],a:0,exp:"Tetra es una capitana pirata que m\u00e1s tarde se revela como una encarnaci\u00f3n de la princesa Zelda.",extra:"Tetra es una de las versiones m\u00e1s carism\u00e1ticas de Zelda: independiente, sarc\u00e1stica y muy activa dentro de la historia."},
  {t:"m",q:"\u00bfQu\u00e9 juego muestra a Link transform\u00e1ndose en lobo?",o:["Twilight Princess", "Skyward Sword", "A Link Between Worlds", "Spirit Tracks"],a:0,exp:"En Twilight Princess, Link puede transformarse en lobo al entrar en el Crep\u00fasculo.",extra:"La forma de lobo cambia la exploraci\u00f3n y combate, permitiendo rastrear olores, excavar y usar sentidos especiales."},
  {t:"m",q:"\u00bfQu\u00e9 personaje acompa\u00f1a a Link en Twilight Princess?",o:["Midna", "Navi", "Tatl", "Fi"],a:0,exp:"Midna acompa\u00f1a a Link durante Twilight Princess y es clave para la historia del Reino del Crep\u00fasculo.",extra:"Midna es uno de los acompa\u00f1antes m\u00e1s queridos de la saga por su evoluci\u00f3n: empieza manipuladora y sarc\u00e1stica, pero termina mostrando gran nobleza."},
  {t:"m",q:"\u00bfQu\u00e9 villano usurpa el trono del Reino del Crep\u00fasculo?",o:["Zant", "Vaati", "Ghirahim", "Agahnim"],a:0,exp:"Zant usurpa el trono del Reino del Crep\u00fasculo con ayuda de Ganondorf.",extra:"Zant parece un villano fr\u00edo y ceremonial, pero m\u00e1s adelante revela una personalidad mucho m\u00e1s inestable y desesperada."},
  {t:"m",q:"\u00bfQu\u00e9 criatura acompa\u00f1a a Link como espada en Skyward Sword?",o:["Fi", "Midna", "Navi", "Ciela"],a:0,exp:"Fi es el esp\u00edritu de la espada que acompa\u00f1a a Link en Skyward Sword.",extra:"Fi est\u00e1 ligada al origen de la Master Sword y representa una gu\u00eda l\u00f3gica, casi artificial, en contraste con acompa\u00f1antes m\u00e1s emocionales."},
  {t:"m",q:"\u00bfQu\u00e9 juego cuenta el origen de la Master Sword dentro de la cronolog\u00eda?",o:["Skyward Sword", "Ocarina of Time", "The Wind Waker", "A Link to the Past"],a:0,exp:"Skyward Sword narra el origen de la Master Sword.",extra:"Tambi\u00e9n establece elementos importantes del ciclo eterno entre el h\u00e9roe, la diosa y la maldici\u00f3n del mal."},
  {t:"m",q:"\u00bfCu\u00e1l es la isla celestial de inicio en Skyward Sword?",o:["Alt\u00e1rea", "Isla Initia", "Kakariko", "Outset"],a:0,exp:"Skyward Sword comienza en Alt\u00e1rea, una comunidad flotante en el cielo.",extra:"La separaci\u00f3n entre cielo y superficie estructura el viaje de Link, que debe descubrir el mundo inferior y sus secretos antiguos."},
  {t:"m",q:"\u00bfQu\u00e9 ave montan los habitantes de Alt\u00e1rea?",o:["Pel\u00edcaros", "Nebur\u00edes", "Loftwings", "Ritos"],a:2,exp:"Los Loftwings son grandes aves que sirven como compa\u00f1eros y monturas en Skyward Sword.",extra:"El v\u00ednculo entre Link y su Loftwing rojo es parte esencial del inicio del juego y de su identidad como caballero de Alt\u00e1rea."},
  {t:"m",q:"\u00bfQu\u00e9 villano teatral persigue a Zelda en Skyward Sword?",o:["Ghirahim", "Zant", "Vaati", "Yuga"],a:0,exp:"Ghirahim es el antagonista principal durante gran parte de Skyward Sword.",extra:"Ghirahim destaca por su personalidad extravagante, inquietante y obsesiva, adem\u00e1s de su conexi\u00f3n con la espada de su amo."},
  {t:"m",q:"\u00bfQu\u00e9 entidad demon\u00edaca est\u00e1 ligada al origen de la maldici\u00f3n recurrente de la saga?",o:["Demise", "Bellum", "Malladus", "Onox"],a:0,exp:"Demise es una entidad demon\u00edaca derrotada en Skyward Sword cuya maldici\u00f3n anticipa el ciclo de conflicto.",extra:"Su odio renace a trav\u00e9s de eras, explicando de forma m\u00edtica la persistencia de amenazas como Ganon."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Super Nintendo presenta el Mundo de la Luz y el Mundo Oscuro?",o:["A Link to the Past", "Link\u2019s Awakening", "Oracle of Seasons", "The Minish Cap"],a:0,exp:"A Link to the Past alterna entre el Mundo de la Luz y el Mundo Oscuro.",extra:"Este juego defini\u00f3 muchas bases de Zelda 2D: mazmorras complejas, objetos clave, exploraci\u00f3n abierta y una estructura de mundo doble."},
  {t:"m",q:"\u00bfQu\u00e9 villano mago aparece en A Link to the Past como sirviente de Ganon?",o:["Agahnim", "Vaati", "Yuga", "Ghirahim"],a:0,exp:"Agahnim act\u00faa como antagonista principal durante la primera parte de A Link to the Past.",extra:"Su papel como mago usurpador y manipulador prepara el regreso de Ganon desde el Mundo Oscuro."},
  {t:"m",q:"\u00bfQu\u00e9 juego ocurre en la misteriosa Isla Koholint?",o:["Link\u2019s Awakening", "Oracle of Ages", "Phantom Hourglass", "Spirit Tracks"],a:0,exp:"Link\u2019s Awakening transcurre en la Isla Koholint.",extra:"Es una de las historias m\u00e1s melanc\u00f3licas de la saga, porque la naturaleza de la isla cambia por completo el sentido de la aventura."},
  {t:"m",q:"\u00bfQu\u00e9 criatura duerme dentro del huevo gigante de Koholint?",o:["Pez del Viento", "Drag\u00f3n del Cielo", "Gran Deku", "Leviat\u00e1n Zora"],a:0,exp:"El Pez del Viento duerme dentro del huevo en la cima de la monta\u00f1a de Koholint.",extra:"Despertarlo es el objetivo central del juego, aunque hacerlo tiene consecuencias emocionales profundas para la isla y sus habitantes."},
  {t:"m",q:"\u00bfQu\u00e9 personaje de Link\u2019s Awakening canta la Balada del Pez del Viento?",o:["Marin", "Malon", "Tetra", "Din"],a:0,exp:"Marin canta la Balada del Pez del Viento.",extra:"Marin es uno de los personajes m\u00e1s recordados del juego por su ternura, su deseo de conocer el mundo exterior y su v\u00ednculo con Link."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Game Boy Advance explora el mundo diminuto de los Minish?",o:["The Minish Cap", "Four Swords Adventures", "Oracle of Ages", "Spirit Tracks"],a:0,exp:"The Minish Cap presenta a los Minish, una raza diminuta que ayuda a los humanos.",extra:"El juego usa el cambio de tama\u00f1o como mec\u00e1nica central, permitiendo ver lugares cotidianos desde una escala completamente distinta."},
  {t:"m",q:"\u00bfC\u00f3mo se llama el gorro parlante de The Minish Cap?",o:["Ezlo", "Fi", "Daphnes", "Ciela"],a:0,exp:"Ezlo es el gorro parlante que acompa\u00f1a a Link en The Minish Cap.",extra:"Ezlo permite a Link reducirse al tama\u00f1o Minish y tambi\u00e9n tiene una historia personal ligada al villano Vaati."},
  {t:"m",q:"\u00bfQu\u00e9 villano aparece en The Minish Cap y Four Swords?",o:["Vaati", "Zant", "Ganon II", "Bellum"],a:0,exp:"Vaati es un villano recurrente asociado a The Minish Cap y la saga Four Swords.",extra:"Vaati suele estar relacionado con magia, viento y ambici\u00f3n, funcionando como amenaza distinta a Ganondorf."},
  {t:"m",q:"\u00bfQu\u00e9 objeto divide a Link en varios h\u00e9roes en Four Swords?",o:["Four Sword", "Master Sword", "Phantom Sword", "Gilded Sword"],a:0,exp:"La Four Sword permite dividir a Link en cuatro versiones.",extra:"Esta mec\u00e1nica convirti\u00f3 Four Swords en una experiencia centrada en cooperaci\u00f3n, puzzles multijugador y coordinaci\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Nintendo DS contin\u00faa la historia del Link de Wind Waker?",o:["Phantom Hourglass", "Spirit Tracks", "Oracle of Seasons", "Tri Force Heroes"],a:0,exp:"Phantom Hourglass contin\u00faa las aventuras mar\u00edtimas de Link y Tetra tras The Wind Waker.",extra:"El juego usa controles t\u00e1ctiles y presenta el Barco de Linebeck como parte central de la exploraci\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 personaje cobarde y ambicioso acompa\u00f1a a Link en Phantom Hourglass?",o:["Linebeck", "Ravio", "Tingle", "Beedle"],a:0,exp:"Linebeck acompa\u00f1a a Link en Phantom Hourglass como capit\u00e1n de barco.",extra:"Linebeck empieza siendo ego\u00edsta y miedoso, pero su arco lo convierte en uno de los personajes m\u00e1s queridos de la etapa DS."},
  {t:"m",q:"\u00bfQu\u00e9 juego de DS usa trenes como medio principal de transporte?",o:["Spirit Tracks", "Phantom Hourglass", "The Minish Cap", "Oracle of Ages"],a:0,exp:"Spirit Tracks usa un tren como sistema principal para recorrer el mundo.",extra:"La idea de v\u00edas espirituales le da al juego una identidad muy distinta dentro de la saga, reemplazando el barco por rutas ferroviarias."},
  {t:"m",q:"\u00bfQu\u00e9 papel tiene Zelda en Spirit Tracks durante gran parte del juego?",o:["Acompa\u00f1a a Link como esp\u00edritu", "Es la villana principal", "No aparece", "Se convierte en hada"],a:0,exp:"En Spirit Tracks, Zelda acompa\u00f1a a Link en forma espiritual tras perder su cuerpo.",extra:"Es una de las Zeldas m\u00e1s activas y expresivas de la saga, con participaci\u00f3n constante en puzzles y narrativa."},
  {t:"m",q:"\u00bfQu\u00e9 juego de 3DS funciona como sucesor espiritual de A Link to the Past?",o:["A Link Between Worlds", "Tri Force Heroes", "Ocarina of Time 3D", "Majora\u2019s Mask 3D"],a:0,exp:"A Link Between Worlds retoma el mundo de A Link to the Past y lo transforma con nuevas mec\u00e1nicas.",extra:"Su gran innovaci\u00f3n es permitir que Link se convierta en pintura y se mueva por paredes, abriendo puzzles muy creativos."},
  {t:"m",q:"\u00bfQu\u00e9 reino paralelo aparece en A Link Between Worlds?",o:["Lorule", "Termina", "Labrynna", "Holodrum"],a:0,exp:"Lorule es un reino paralelo a Hyrule en A Link Between Worlds.",extra:"Lorule funciona como espejo oscuro de Hyrule, con su propia princesa, su propia historia y una Trifuerza destruida."},
  {t:"m",q:"\u00bfQu\u00e9 personaje alquila objetos a Link en A Link Between Worlds?",o:["Ravio", "Beedle", "Tingle", "Sahasrahla"],a:0,exp:"Ravio alquila y vende objetos clave a Link.",extra:"Este sistema permite abordar mazmorras en un orden m\u00e1s libre que en muchos Zelda tradicionales."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Zelda para NES inici\u00f3 la saga en 1986?",o:["The Legend of Zelda", "Zelda II: The Adventure of Link", "A Link to the Past", "Link\u2019s Awakening"],a:0,exp:"The Legend of Zelda para NES fue el primer juego de la saga.",extra:"Su \u00e9nfasis en exploraci\u00f3n, secretos y libertad fue revolucionario para su \u00e9poca y dej\u00f3 una estructura que Breath of the Wild retomar\u00eda d\u00e9cadas despu\u00e9s."},
  {t:"m",q:"\u00bfQu\u00e9 segundo juego de NES incorpor\u00f3 desplazamiento lateral y elementos RPG m\u00e1s marcados?",o:["Zelda II: The Adventure of Link", "A Link to the Past", "Link\u2019s Awakening", "Oracle of Ages"],a:0,exp:"Zelda II: The Adventure of Link cambi\u00f3 mucho la f\u00f3rmula con combate lateral y experiencia.",extra:"Es una de las entregas m\u00e1s at\u00edpicas y dif\u00edciles de la saga, pero introdujo elementos importantes como magia y pueblos con NPCs."},
  {t:"m",q:"\u00bfQu\u00e9 frase famosa de un anciano aparece al inicio del primer Zelda?",o:["It\u2019s dangerous to go alone! Take this.", "Hey! Listen!", "You\u2019ve met with a terrible fate.", "Courage need not be remembered."],a:0,exp:"El anciano entrega una espada a Link diciendo \u201cIt\u2019s dangerous to go alone! Take this.\u201d",extra:"La frase se volvi\u00f3 una de las citas m\u00e1s famosas de la historia de los videojuegos."},
  {t:"m",q:"\u00bfQu\u00e9 vendedor recurrente suele viajar con una gran mochila o tienda?",o:["Beedle", "Tingle", "Ravio", "Guru-Guru"],a:0,exp:"Beedle es un comerciante recurrente en varios juegos de Zelda.",extra:"Puede aparecer en barcos, puestos, globos o establos, pero casi siempre cumple el rol de vendedor amable y algo exc\u00e9ntrico."},
  {t:"m",q:"\u00bfQu\u00e9 personaje obsesionado con hadas viste de verde y aparece en varios juegos?",o:["Tingle", "Linebeck", "Ravio", "Gondo"],a:0,exp:"Tingle es un personaje exc\u00e9ntrico obsesionado con hadas y mapas.",extra:"Tingle divide opiniones entre fans, pero es uno de los secundarios m\u00e1s reconocibles por su personalidad extra\u00f1a y su frase \u201cKooloo-Limpah\u201d."},
  {t:"m",q:"\u00bfQu\u00e9 enemigo com\u00fan suele aparecer como esqueleto armado?",o:["Stalfos", "Moblin", "Octorok", "Keese"],a:0,exp:"Los Stalfos son enemigos esquel\u00e9ticos que suelen combatir con armas.",extra:"Aparecen en muchas entregas y suelen funcionar como enemigos m\u00e1s resistentes que criaturas b\u00e1sicas."},
  {t:"m",q:"\u00bfQu\u00e9 enemigo dispara rocas o proyectiles desde el agua o tierra?",o:["Octorok", "Lizalfos", "Darknut", "Redead"],a:0,exp:"Los Octorok son enemigos cl\u00e1sicos que disparan proyectiles.",extra:"Son de los enemigos m\u00e1s antiguos de la saga, presentes desde el primer The Legend of Zelda."},
  {t:"m",q:"\u00bfQu\u00e9 enemigos parecidos a murci\u00e9lagos aparecen en muchas mazmorras?",o:["Keese", "ChuChu", "Poe", "Like Like"],a:0,exp:"Los Keese son enemigos voladores similares a murci\u00e9lagos.",extra:"Pueden tener variantes de fuego, hielo o electricidad seg\u00fan el juego, haciendo que un enemigo simple siga siendo molesto."},
  {t:"m",q:"\u00bfQu\u00e9 enemigo puede tragarse a Link y robarle equipo en algunos juegos?",o:["Like Like", "Moblin", "Gibdo", "Peahat"],a:0,exp:"Los Like Like son enemigos capaces de tragarse a Link y, en algunos juegos, robar escudos o t\u00fanicas.",extra:"Son recordados con terror por jugadores cl\u00e1sicos porque perder un escudo importante pod\u00eda ser muy frustrante."},
  {t:"m",q:"\u00bfQu\u00e9 enemigo momificado puede paralizar a Link con un grito?",o:["Gibdo", "Octorok", "Bokoblin", "Deku Baba"],a:0,exp:"Los Gibdo son enemigos momificados que suelen paralizar a Link antes de atacarlo.",extra:"En varios juegos est\u00e1n relacionados con zonas malditas, cementerios o templos oscuros."},
  {t:"m",q:"\u00bfQu\u00e9 enemigo zombi de Ocarina of Time es famoso por su grito paralizante?",o:["Redead", "Stalfos", "Poe", "Skulltula"],a:0,exp:"Los Redead paralizan a Link con un grito y luego lo atacan.",extra:"Son de los enemigos m\u00e1s inquietantes de Ocarina of Time por su sonido, animaci\u00f3n y presencia en lugares devastados."},
  {t:"m",q:"\u00bfQu\u00e9 ara\u00f1as doradas coleccionables aparecen en Ocarina of Time?",o:["Gold Skulltulas", "Golden Keese", "Royal Spiders", "Sun Tokens"],a:0,exp:"Las Gold Skulltulas son ara\u00f1as doradas coleccionables en Ocarina of Time.",extra:"Al reunir sus tokens, Link ayuda a una familia maldita en Kakariko y obtiene recompensas."},
  {t:"m",q:"\u00bfQu\u00e9 aldea aparece frecuentemente como asentamiento importante de Hyrule?",o:["Kakariko", "Pueblo Paleta", "Narshe", "Onett"],a:0,exp:"Kakariko es una aldea recurrente en m\u00faltiples entregas de Zelda.",extra:"Su rol cambia seg\u00fan el juego, pero suele estar ligada a los Sheikah, secretos antiguos y personajes clave."},
  {t:"m",q:"\u00bfQu\u00e9 lago famoso aparece en varias versiones de Hyrule?",o:["Lago Hylia", "Lago Macalania", "Lago Valor", "Lago Lunar"],a:0,exp:"El Lago Hylia es uno de los lugares recurrentes de Hyrule.",extra:"Suele conectarse con los Zora, templos acu\u00e1ticos, pesca y zonas de exploraci\u00f3n importantes."},
  {t:"m",q:"\u00bfQu\u00e9 templo de Ocarina of Time es famoso por su dificultad y uso de botas de hierro?",o:["Templo del Agua", "Templo del Fuego", "Templo del Bosque", "Templo del Esp\u00edritu"],a:0,exp:"El Templo del Agua es famoso por sus cambios de nivel de agua y uso de botas de hierro.",extra:"Durante a\u00f1os fue uno de los templos m\u00e1s comentados por su complejidad, especialmente en la versi\u00f3n original de Nintendo 64."},
  {t:"m",q:"\u00bfQui\u00e9n es el jefe del Templo del Bosque en Ocarina of Time?",o:["Phantom Ganon", "Volvagia", "Morpha", "Bongo Bongo"],a:0,exp:"Phantom Ganon es el jefe del Templo del Bosque.",extra:"La pelea juega con cuadros, ilusiones y una versi\u00f3n fantasmag\u00f3rica de Ganondorf."},
  {t:"m",q:"\u00bfQu\u00e9 drag\u00f3n es jefe del Templo del Fuego en Ocarina of Time?",o:["Volvagia", "Valoo", "Argorok", "Dinraal"],a:0,exp:"Volvagia es el drag\u00f3n que Link enfrenta en el Templo del Fuego.",extra:"Su historia est\u00e1 ligada a los Goron y a una amenaza ancestral despertada por Ganondorf."},
  {t:"m",q:"\u00bfQu\u00e9 jefe acu\u00e1tico aparece en el Templo del Agua de Ocarina of Time?",o:["Morpha", "Gyorg", "Barinade", "Tentalus"],a:0,exp:"Morpha es el jefe del Templo del Agua.",extra:"Es una criatura acu\u00e1tica que usa tent\u00e1culos de agua para atacar a Link en una arena rodeada de l\u00edquido."},
  {t:"m",q:"\u00bfQu\u00e9 jefe sombr\u00edo aparece en el Templo de las Sombras?",o:["Bongo Bongo", "Gohma", "Twinrova", "King Dodongo"],a:0,exp:"Bongo Bongo es el jefe del Templo de las Sombras en Ocarina of Time.",extra:"Su dise\u00f1o extra\u00f1o y la arena sobre un tambor gigante lo convierten en uno de los jefes m\u00e1s memorables del juego."},
  {t:"m",q:"\u00bfQu\u00e9 brujas gemelas son jefas del Templo del Esp\u00edritu?",o:["Twinrova", "Kotake y Koume", "Las dos anteriores", "Nabooru y Ruto"],a:2,exp:"Twinrova es la forma combinada de las brujas Kotake y Koume.",extra:"Una usa hielo y la otra fuego; la pelea exige absorber y devolver elementos con el Escudo Espejo."},
  {t:"m",q:"\u00bfQu\u00e9 raza vegetal aparece como ni\u00f1os del bosque en The Wind Waker?",o:["Koroks", "Kokiri", "Minish", "Deku"],a:0,exp:"En The Wind Waker, los Koroks aparecen como peque\u00f1as criaturas vegetales del bosque.",extra:"Se sugiere que est\u00e1n relacionados con los Kokiri, adaptados al mundo inundado."},
  {t:"m",q:"\u00bfQu\u00e9 raza de aves aparece en The Wind Waker y Breath of the Wild?",o:["Rito", "Zora", "Gerudo", "Twili"],a:0,exp:"Los Rito son una raza aviar presente en varias entregas.",extra:"Su origen y dise\u00f1o var\u00edan entre juegos, pero suelen estar vinculados a vuelo, mensajer\u00eda, m\u00fasica o arquer\u00eda."},
  {t:"m",q:"\u00bfQu\u00e9 drag\u00f3n rojo protege Isla Drag\u00f3n en The Wind Waker?",o:["Valoo", "Dinraal", "Volvagia", "Eldin"],a:0,exp:"Valoo es el drag\u00f3n que vive en Isla Drag\u00f3n.",extra:"Su v\u00ednculo con los Rito es esencial, ya que sus escamas est\u00e1n relacionadas con el crecimiento de sus alas."},
  {t:"m",q:"\u00bfQu\u00e9 sacerdotisa Rito toca el arpa en The Wind Waker?",o:["Medli", "Makar", "Komali", "Laruto"],a:0,exp:"Medli es una Rito que toca el arpa y cumple un papel importante como sabia.",extra:"Su mazmorra ligada al Templo de la Tierra mezcla m\u00fasica, luz, cooperaci\u00f3n y herencia espiritual."},
  {t:"m",q:"\u00bfQu\u00e9 Korok toca el viol\u00edn en The Wind Waker?",o:["Makar", "Hestu", "Saria", "Fado"],a:0,exp:"Makar es un Korok m\u00fasico que toca el viol\u00edn.",extra:"Makar se convierte en sabio del Templo del Viento y ayuda a restaurar el poder de la Master Sword."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Wii U y Switch apost\u00f3 por un Hyrule abierto y f\u00edsica sist\u00e9mica?",o:["Breath of the Wild", "Twilight Princess", "Skyward Sword", "The Wind Waker HD"],a:0,exp:"Breath of the Wild reinvent\u00f3 Zelda con mundo abierto, f\u00edsica, qu\u00edmica y exploraci\u00f3n libre.",extra:"El juego recupera la sensaci\u00f3n de descubrimiento del Zelda original, pero con sistemas modernos que permiten resolver problemas de muchas formas."},
  {t:"m",q:"\u00bfC\u00f3mo se llama la tableta tecnol\u00f3gica que usa Link en Breath of the Wild?",o:["Sheikah Slate", "Purah Pad", "Ocarina Sheikah", "Triforce Tablet"],a:0,exp:"La Sheikah Slate permite usar runas, mapa y funciones tecnol\u00f3gicas antiguas.",extra:"Es una herramienta clave para interactuar con santuarios, torres y mecanismos Sheikah."},
  {t:"m",q:"\u00bfQu\u00e9 estructura peque\u00f1a contiene puzzles y recompensas en Breath of the Wild?",o:["Santuarios", "Fortalezas", "Dojo Deku", "C\u00e1maras Zora"],a:0,exp:"Los santuarios contienen pruebas de puzzles, combate o f\u00edsica.",extra:"Al completarlos, Link obtiene s\u00edmbolos de val\u00eda que puede cambiar por corazones o resistencia."},
  {t:"m",q:"\u00bfQu\u00e9 torres revelan partes del mapa en Breath of the Wild?",o:["Torres Sheikah", "Torres Gerudo", "Faros Hylianos", "Obeliscos Zonai"],a:0,exp:"Las Torres Sheikah desbloquean zonas del mapa regional.",extra:"Subirlas funciona como desaf\u00edo de escalada, resistencia y exploraci\u00f3n, adem\u00e1s de ofrecer vistas enormes del terreno."},
  {t:"m",q:"\u00bfQu\u00e9 bestias mec\u00e1nicas gigantes son centrales en Breath of the Wild?",o:["Bestias Divinas", "Guardianes Mayores", "Titanes Hylianos", "M\u00e1quinas de Ganon"],a:0,exp:"Las Bestias Divinas son enormes m\u00e1quinas antiguas controladas por Ganon al inicio del juego.",extra:"Cada una est\u00e1 ligada a un pueblo de Hyrule y a un campe\u00f3n ca\u00eddo."},
  {t:"m",q:"\u00bfQu\u00e9 Bestia Divina est\u00e1 asociada a los Zora?",o:["Vah Ruta", "Vah Rudania", "Vah Medoh", "Vah Naboris"],a:0,exp:"Vah Ruta es la Bestia Divina asociada al pueblo Zora.",extra:"Tiene forma de elefante y su historia est\u00e1 ligada a Mipha, campeona Zora y amiga cercana de Link."},
  {t:"m",q:"\u00bfQu\u00e9 Bestia Divina est\u00e1 asociada a los Goron?",o:["Vah Rudania", "Vah Ruta", "Vah Medoh", "Vah Naboris"],a:0,exp:"Vah Rudania es la Bestia Divina vinculada a los Goron.",extra:"Tiene forma de salamandra y se encuentra en la zona volc\u00e1nica de la Monta\u00f1a de la Muerte."},
  {t:"m",q:"\u00bfQu\u00e9 Bestia Divina est\u00e1 asociada a los Rito?",o:["Vah Medoh", "Vah Ruta", "Vah Rudania", "Vah Naboris"],a:0,exp:"Vah Medoh es la Bestia Divina asociada a los Rito.",extra:"Tiene forma de ave y su campe\u00f3n fue Revali, uno de los personajes m\u00e1s orgullosos del grupo."},
  {t:"m",q:"\u00bfQu\u00e9 Bestia Divina est\u00e1 asociada a las Gerudo?",o:["Vah Naboris", "Vah Medoh", "Vah Ruta", "Vah Rudania"],a:0,exp:"Vah Naboris es la Bestia Divina vinculada a las Gerudo.",extra:"Tiene forma de camello y se mueve por el desierto generando tormentas el\u00e9ctricas."},
  {t:"m",q:"\u00bfQui\u00e9n es la campeona Zora en Breath of the Wild?",o:["Mipha", "Urbosa", "Daruk", "Revali"],a:0,exp:"Mipha es la campeona Zora y piloto de Vah Ruta.",extra:"Su poder de curaci\u00f3n y su v\u00ednculo afectivo con Link la convierten en una de las figuras m\u00e1s emotivas del juego."},
  {t:"m",q:"\u00bfQui\u00e9n es el campe\u00f3n Goron en Breath of the Wild?",o:["Daruk", "Revali", "Sidon", "Yunobo"],a:0,exp:"Daruk es el campe\u00f3n Goron y piloto de Vah Rudania.",extra:"Daruk es fuerte, leal y alegre; su protecci\u00f3n especial ayuda a Link bloqueando ataques."},
  {t:"m",q:"\u00bfQui\u00e9n es el campe\u00f3n Rito en Breath of the Wild?",o:["Revali", "Teba", "Kass", "Komali"],a:0,exp:"Revali es el campe\u00f3n Rito y piloto de Vah Medoh.",extra:"Es famoso por su habilidad a\u00e9rea y por una personalidad orgullosa que contrasta con su enorme talento."},
  {t:"m",q:"\u00bfQui\u00e9n es la campeona Gerudo en Breath of the Wild?",o:["Urbosa", "Riju", "Nabooru", "Buliara"],a:0,exp:"Urbosa es la campeona Gerudo y piloto de Vah Naboris.",extra:"Urbosa tiene una conexi\u00f3n especial con Zelda y representa fuerza, elegancia y liderazgo maternal."},
  {t:"m",q:"\u00bfQu\u00e9 pr\u00edncipe Zora ayuda a Link en Breath of the Wild?",o:["Sidon", "Dorephan", "Muzu", "Ralis"],a:0,exp:"Sidon ayuda a Link a llegar hasta Vah Ruta.",extra:"Sidon se volvi\u00f3 muy popular por su energ\u00eda positiva, su carisma y su confianza absoluta en Link."},
  {t:"m",q:"\u00bfQu\u00e9 villano toma forma de corrupci\u00f3n oscura en Breath of the Wild?",o:["Calamity Ganon", "Vaati", "Majora", "Bellum"],a:0,exp:"Calamity Ganon es la manifestaci\u00f3n corrupta de Ganon que amenaza Hyrule.",extra:"M\u00e1s que un villano conversador, funciona como una fuerza de malicia que infecta m\u00e1quinas, castillo y bestias antiguas."},
  {t:"m",q:"\u00bfQu\u00e9 enemigos mec\u00e1nicos disparan l\u00e1seres en Breath of the Wild?",o:["Guardianes", "Lynels", "Hinox", "Talus"],a:0,exp:"Los Guardianes son m\u00e1quinas antiguas corrompidas que disparan rayos l\u00e1ser.",extra:"Al principio son aterradores, pero con escudos, parrys y buen equipo pueden convertirse en fuente de materiales valiosos."},
  {t:"m",q:"\u00bfQu\u00e9 enemigo centauro es uno de los m\u00e1s peligrosos en Breath of the Wild?",o:["Lynel", "Bokoblin", "Moblin", "Hinox"],a:0,exp:"Los Lynels son enemigos extremadamente fuertes, r\u00e1pidos y resistentes.",extra:"Enfrentar Lynels es una prueba de dominio del combate: esquivas perfectas, parrys, arco, resistencia y conocimiento de patrones."},
  {t:"m",q:"\u00bfQu\u00e9 gigante dormil\u00f3n aparece como miniboss en varios lugares?",o:["Hinox", "Talus", "Molduga", "Stalnox"],a:0,exp:"Los Hinox son gigantes c\u00edclopes que suelen dormir hasta que Link se acerca.",extra:"A menudo llevan armas colgadas del cuello, y golpear su ojo es una estrategia b\u00e1sica para vencerlos."},
  {t:"m",q:"\u00bfQu\u00e9 jefe de piedra se camufla como roca gigante?",o:["Stone Talus", "Hinox", "Lynel", "Molduga"],a:0,exp:"El Stone Talus parece una formaci\u00f3n rocosa hasta que despierta.",extra:"Para derrotarlo hay que atacar su dep\u00f3sito mineral, escalando sobre su cuerpo o usando flechas y bombas."},
  {t:"m",q:"\u00bfQu\u00e9 monstruo del desierto detecta vibraciones bajo la arena?",o:["Molduga", "Talus", "Hinox", "Lynel"],a:0,exp:"La Molduga vive bajo la arena y detecta movimientos o vibraciones.",extra:"Combatirla suele implicar atraerla con bombas y atacarla cuando salta o queda expuesta."},
  {t:"m",q:"\u00bfQu\u00e9 objeto permite a Link planear en Breath of the Wild?",o:["Paravela", "Capa Rito", "\u00c9litros", "Ala Sheikah"],a:0,exp:"La paravela permite planear desde alturas.",extra:"Se obtiene al inicio tras completar la meseta, y transforma por completo la exploraci\u00f3n vertical del mundo."},
  {t:"m",q:"\u00bfQu\u00e9 sistema limita cu\u00e1nto puede escalar o correr Link?",o:["Resistencia", "Magia", "Durabilidad espiritual", "Carga"],a:0,exp:"La resistencia limita acciones como correr, escalar, nadar y planear.",extra:"Mejorar la resistencia puede ser incluso m\u00e1s \u00fatil que aumentar corazones para explorar zonas dif\u00edciles."},
  {t:"m",q:"\u00bfQu\u00e9 ocurre con muchas armas en Breath of the Wild?",o:["Se rompen con el uso", "Suben de nivel infinitamente", "No pueden cambiarse", "Solo funcionan en mazmorras"],a:0,exp:"La mayor\u00eda de armas tienen durabilidad y se rompen tras usarse.",extra:"Este sistema anima a improvisar, probar armas distintas y usar el entorno, aunque tambi\u00e9n fue muy debatido entre jugadores."},
  {t:"m",q:"\u00bfQu\u00e9 juego es secuela directa de Breath of the Wild?",o:["Tears of the Kingdom", "Skyward Sword", "Age of Calamity", "A Link Between Worlds"],a:0,exp:"Tears of the Kingdom contin\u00faa la historia y el mundo de Breath of the Wild.",extra:"Expande Hyrule con islas celestes, subsuelo y nuevas habilidades basadas en construcci\u00f3n, fusi\u00f3n y manipulaci\u00f3n f\u00edsica."},
  {t:"m",q:"\u00bfQu\u00e9 brazo obtiene Link al inicio de Tears of the Kingdom?",o:["Brazo de Rauru", "Brazo de Ganon", "Brazo Sheikah", "Brazo de Midna"],a:0,exp:"Link recibe el brazo de Rauru, que le otorga nuevas habilidades.",extra:"Este brazo reemplaza funciones de la Sheikah Slate con poderes como Ultramano, Combinaci\u00f3n, Infiltraci\u00f3n y Retroceso."},
  {t:"m",q:"\u00bfQu\u00e9 habilidad permite unir objetos en Tears of the Kingdom?",o:["Ultramano", "Ascender", "Retroceso", "Furia de Urbosa"],a:0,exp:"Ultramano permite agarrar, mover y unir objetos.",extra:"Es la base del sistema de construcci\u00f3n del juego, permitiendo crear veh\u00edculos, puentes, m\u00e1quinas y soluciones absurdamente creativas."},
  {t:"m",q:"\u00bfQu\u00e9 habilidad permite atravesar techos hacia arriba en Tears of the Kingdom?",o:["Infiltraci\u00f3n", "Combinaci\u00f3n", "Paravela", "Magnesis"],a:0,exp:"Infiltraci\u00f3n permite subir a trav\u00e9s de superficies superiores v\u00e1lidas.",extra:"Esta habilidad cambia la lectura del espacio: cuevas, edificios y monta\u00f1as pueden resolverse buscando techos en lugar de caminos tradicionales."},
  {t:"m",q:"\u00bfQu\u00e9 habilidad rebobina el movimiento de objetos en Tears of the Kingdom?",o:["Retroceso", "Estasis", "Cryonis", "Ascenso"],a:0,exp:"Retroceso permite invertir temporalmente el movimiento de ciertos objetos.",extra:"Se usa tanto en puzzles como en combate y exploraci\u00f3n, por ejemplo para subir en rocas ca\u00eddas desde el cielo."},
  {t:"m",q:"\u00bfQu\u00e9 habilidad permite fusionar objetos con armas o escudos?",o:["Combinaci\u00f3n", "Ultramano", "Infiltraci\u00f3n", "Duplicaci\u00f3n"],a:0,exp:"Combinaci\u00f3n permite unir materiales a armas, escudos o flechas.",extra:"Este sistema reemplaza parte de la l\u00f3gica tradicional de armas, haciendo que casi cualquier objeto pueda tener utilidad creativa o ofensiva."},
  {t:"m",q:"\u00bfQu\u00e9 civilizaci\u00f3n antigua es central en Tears of the Kingdom?",o:["Zonai", "Twili", "Minish", "Kokiri"],a:0,exp:"Los Zonai son una civilizaci\u00f3n antigua clave en Tears of the Kingdom.",extra:"Su tecnolog\u00eda, arquitectura y relaci\u00f3n con los or\u00edgenes de Hyrule atraviesan la historia del juego."},
  {t:"m",q:"\u00bfQui\u00e9n es Rauru en Tears of the Kingdom?",o:["Un rey Zonai fundador de Hyrule", "Un comerciante Rito", "Un sabio Goron", "Un villano Gerudo"],a:0,exp:"Rauru es un Zonai y figura fundacional del antiguo reino de Hyrule.",extra:"Su papel conecta la historia antigua con el presente de Link y Zelda."},
  {t:"m",q:"\u00bfQui\u00e9n es Sonia en Tears of the Kingdom?",o:["La reina fundadora de Hyrule", "Una campeona Zora", "Una pirata", "Una sacerdotisa Rito"],a:0,exp:"Sonia es la reina de Hyrule en la era antigua y est\u00e1 ligada al poder del tiempo.",extra:"Su relaci\u00f3n con Rauru y Zelda es fundamental para entender la historia ancestral del juego."},
  {t:"m",q:"\u00bfQu\u00e9 zona subterr\u00e1nea enorme se a\u00f1ade en Tears of the Kingdom?",o:["El Subsuelo", "El Reino del Crep\u00fasculo", "Lorule", "Termina"],a:0,exp:"Tears of the Kingdom a\u00f1ade el Subsuelo como una gran regi\u00f3n bajo Hyrule.",extra:"El Subsuelo invierte la geograf\u00eda de la superficie y a\u00f1ade oscuridad, miner\u00eda, ra\u00edces luminosas y amenazas corrompidas."},
  {t:"m",q:"\u00bfQu\u00e9 sustancia oscura reduce corazones temporalmente en Tears of the Kingdom?",o:["Gloom", "Malicia", "Veneno Zora", "Niebla Deku"],a:0,exp:"El Gloom da\u00f1a a Link reduciendo corazones m\u00e1ximos temporalmente.",extra:"En el Subsuelo, esta mec\u00e1nica vuelve la exploraci\u00f3n m\u00e1s peligrosa y obliga a usar luz, comida especial o regresar a la superficie."},
  {t:"m",q:"\u00bfQu\u00e9 objeto Korok se colecciona en Breath of the Wild y Tears of the Kingdom?",o:["Semillas Korok", "Gemas Zora", "Monedas Hylianas", "Fragmentos Deku"],a:0,exp:"Las semillas Korok se obtienen resolviendo peque\u00f1os puzzles escondidos.",extra:"Se entregan a Hestu para ampliar el inventario de armas, arcos y escudos."},
  {t:"m",q:"\u00bfQui\u00e9n ampl\u00eda el inventario de Link a cambio de semillas Korok?",o:["Hestu", "Beedle", "Kilton", "Ravio"],a:0,exp:"Hestu usa semillas Korok para ampliar espacios de inventario.",extra:"Su baile de celebraci\u00f3n se volvi\u00f3 una recompensa tan memorable como la mejora misma."},
  {t:"m",q:"\u00bfQu\u00e9 establos sirven como puntos de descanso y registro de caballos en Breath of the Wild?",o:["Postas", "Santuarios", "Fuertes", "Casas Sheikah"],a:0,exp:"Las postas permiten registrar caballos, dormir, comprar y recibir informaci\u00f3n.",extra:"Funcionan como peque\u00f1os centros sociales del mundo abierto, conectando exploraci\u00f3n, rumores y viaje."},
  {t:"m",q:"\u00bfQu\u00e9 clan ninja sirve a Ganon en Breath of the Wild?",o:["Clan Yiga", "Clan Sheikah", "Clan Zonai", "Clan Ikana"],a:0,exp:"El Clan Yiga es una facci\u00f3n enemiga que abandon\u00f3 a los Sheikah y sirve a Ganon.",extra:"Sus miembros se disfrazan de viajeros y atacan a Link por sorpresa, mezclando humor y amenaza."},
  {t:"m",q:"\u00bfQui\u00e9n lidera c\u00f3micamente al Clan Yiga en Breath of the Wild?",o:["Maestro Kogg", "Sooga", "Kohga", "Maz Koshia"],a:2,exp:"El Maestro Kohga lidera el Clan Yiga en Breath of the Wild.",extra:"Su pelea mezcla torpeza, teatralidad y peligro, volvi\u00e9ndolo uno de los antagonistas secundarios m\u00e1s recordados."},
  {t:"m",q:"\u00bfQu\u00e9 raza peque\u00f1a de piedra aparece en Breath of the Wild como comerciantes ocultos?",o:["Goron", "Korok", "Kilton", "No hay una raza as\u00ed"],a:3,exp:"No existe una raza peque\u00f1a de piedra comerciante como tal; los comerciantes ocultos suelen ser personajes concretos como Kilton.",extra:"Minecraft tiene criaturas de piedra, pero en Zelda las razas rocosas principales son los Goron, de tama\u00f1o grande y cultura propia."},
  {t:"m",q:"\u00bfQu\u00e9 comerciante nocturno vende objetos relacionados con monstruos en Breath of the Wild?",o:["Kilton", "Beedle", "Hestu", "Robbie"],a:0,exp:"Kilton vende objetos especiales a cambio de partes de monstruos.",extra:"Su tienda Fang and Bone aparece de noche y ofrece m\u00e1scaras y objetos curiosos para jugadores exploradores."},
  {t:"m",q:"\u00bfQu\u00e9 investigadora Sheikah rejuvenecida aparece en Breath of the Wild?",o:["Purah", "Impa", "Paya", "Riju"],a:0,exp:"Purah es una cient\u00edfica Sheikah que termin\u00f3 con apariencia infantil por sus experimentos.",extra:"En Tears of the Kingdom aparece con un rol a\u00fan m\u00e1s visible como l\u00edder de investigaci\u00f3n en el presente."},
  {t:"m",q:"\u00bfQu\u00e9 cient\u00edfico Sheikah trabaja en el laboratorio de Akkala?",o:["Robbie", "Symin", "Dorian", "Kass"],a:0,exp:"Robbie dirige el laboratorio de Akkala y estudia tecnolog\u00eda antigua.",extra:"Su personalidad exc\u00e9ntrica y su relaci\u00f3n con armas ancestrales lo vuelven clave para quienes quieren enfrentarse mejor a Guardianes."},
  {t:"m",q:"\u00bfQu\u00e9 m\u00fasico Rito recorre Hyrule con un acorde\u00f3n en Breath of the Wild?",o:["Kass", "Revali", "Teba", "Makar"],a:0,exp:"Kass es un m\u00fasico Rito que toca el acorde\u00f3n y comparte canciones antiguas.",extra:"Sus melod\u00edas gu\u00edan a Link hacia santuarios y memorias, aportando un tono melanc\u00f3lico al mundo abierto."},
  {t:"m",q:"\u00bfQu\u00e9 objeto permite cocinar platos en Breath of the Wild?",o:["Una olla sobre fuego", "Mesa de cocina", "Horno Sheikah", "Caldero m\u00e1gico obligatorio"],a:0,exp:"Link cocina usando una olla colocada sobre fuego.",extra:"El sistema de cocina permite combinar ingredientes para recuperar vida, obtener resistencia al fr\u00edo, calor, electricidad o mejorar atributos."},
  {t:"m",q:"\u00bfQu\u00e9 efecto ayuda a sobrevivir en zonas fr\u00edas?",o:["Resistencia al fr\u00edo", "Furia el\u00e9ctrica", "Sigilo acu\u00e1tico", "Peso ligero"],a:0,exp:"La resistencia al fr\u00edo protege a Link de da\u00f1o por bajas temperaturas.",extra:"Puede conseguirse con ropa abrigada, comida especial o elixires, especialmente \u00fatil en monta\u00f1as nevadas."},
  {t:"m",q:"\u00bfQu\u00e9 ropa femenina permite a Link entrar en Ciudad Gerudo en Breath of the Wild?",o:["Conjunto Gerudo vai", "Armadura Zora", "T\u00fanica del Campe\u00f3n", "Traje Sheikah"],a:0,exp:"Link necesita el conjunto Gerudo vai para entrar inicialmente en Ciudad Gerudo.",extra:"La ciudad no permite la entrada de hombres, por lo que esta misi\u00f3n mezcla humor, infiltraci\u00f3n y normas culturales Gerudo."},
  {t:"m",q:"\u00bfQu\u00e9 armadura permite nadar mejor y subir cascadas?",o:["Armadura Zora", "Armadura Goron", "Armadura Rito", "Armadura Sheikah"],a:0,exp:"La Armadura Zora mejora la nataci\u00f3n y permite subir cascadas.",extra:"Est\u00e1 ligada a la historia de Mipha y al v\u00ednculo entre Link y los Zora."},
  {t:"m",q:"\u00bfQu\u00e9 armadura protege del calor volc\u00e1nico?",o:["Armadura Ign\u00edfuga", "Armadura Zora", "T\u00fanica del Tiempo", "Set de B\u00e1rbaro"],a:0,exp:"La armadura ign\u00edfuga ayuda a resistir el calor extremo de zonas volc\u00e1nicas.",extra:"Es esencial para explorar la Monta\u00f1a de la Muerte sin quemarse continuamente."},
  {t:"m",q:"\u00bfQu\u00e9 drag\u00f3n espiritual recorre regiones fr\u00edas en Breath of the Wild?",o:["Naydra", "Dinraal", "Farosh", "Valoo"],a:0,exp:"Naydra est\u00e1 asociado al Monte Lanayru y regiones fr\u00edas.",extra:"Los dragones de Breath of the Wild son presencias sagradas que permiten obtener escamas, garras, colmillos y cuernos."},
  {t:"m",q:"\u00bfQu\u00e9 drag\u00f3n est\u00e1 asociado al fuego y la regi\u00f3n de Eldin?",o:["Dinraal", "Naydra", "Farosh", "Volvagia"],a:0,exp:"Dinraal es el drag\u00f3n vinculado al fuego y suele verse cerca de Eldin.",extra:"Su nombre evoca a Din, una de las diosas doradas asociadas al poder."},
  {t:"m",q:"\u00bfQu\u00e9 drag\u00f3n est\u00e1 asociado a electricidad y Farore?",o:["Farosh", "Naydra", "Dinraal", "Valoo"],a:0,exp:"Farosh es el drag\u00f3n el\u00e9ctrico vinculado a Farore.",extra:"Aparece en rutas espec\u00edficas y sus materiales son \u00fatiles para mejoras y recetas."},
  {t:"m",q:"\u00bfQu\u00e9 tres diosas doradas crearon Hyrule seg\u00fan el mito cl\u00e1sico?",o:["Din, Nayru y Farore", "Zelda, Hylia e Impa", "Urbosa, Mipha y Riju", "Kotake, Koume y Twinrova"],a:0,exp:"Din, Nayru y Farore son las diosas doradas creadoras en el mito cl\u00e1sico de Hyrule.",extra:"Din representa poder, Nayru sabidur\u00eda y Farore valor, conceptos que se reflejan en la Trifuerza."},
  {t:"m",q:"\u00bfQu\u00e9 diosa est\u00e1 especialmente ligada a Zelda en Skyward Sword?",o:["Hylia", "Din", "Nayru", "Farore"],a:0,exp:"Hylia es la diosa cuya historia est\u00e1 profundamente conectada con Zelda en Skyward Sword.",extra:"Skyward Sword revela una relaci\u00f3n directa entre Zelda y el legado de Hylia, dando origen a muchos elementos sagrados de la saga."},
  {t:"m",q:"\u00bfQu\u00e9 s\u00edmbolo triangular suele aparecer en manos de Link, Zelda y Ganondorf?",o:["Marca de la Trifuerza", "Sello Sheikah", "Emblema Rito", "Marca Deku"],a:0,exp:"La marca de la Trifuerza aparece vinculada a sus portadores o elegidos.",extra:"Es una se\u00f1al visual de destino, poder sagrado y conexi\u00f3n con las tres virtudes centrales del mito de Hyrule."},
  {t:"m",q:"\u00bfQu\u00e9 l\u00ednea temporal surge cuando Link derrota a Ganon y vuelve a su infancia en Ocarina of Time?",o:["L\u00ednea del Ni\u00f1o", "L\u00ednea del Adulto", "L\u00ednea de la Derrota", "L\u00ednea del Mar"],a:0,exp:"La L\u00ednea del Ni\u00f1o parte del regreso de Link a su infancia tras Ocarina of Time.",extra:"En esta rama se ubican juegos como Majora\u2019s Mask y Twilight Princess."},
  {t:"m",q:"\u00bfQu\u00e9 l\u00ednea temporal contin\u00faa en el mundo donde Link adulto desaparece tras Ocarina of Time?",o:["L\u00ednea del Adulto", "L\u00ednea del Ni\u00f1o", "L\u00ednea de la Derrota", "L\u00ednea de Lorule"],a:0,exp:"La L\u00ednea del Adulto sigue el mundo que Link salv\u00f3 como adulto, pero donde luego ya no est\u00e1 presente.",extra:"The Wind Waker ocurre en esta rama, con Hyrule inundado tras el regreso de Ganon."},
  {t:"m",q:"\u00bfQu\u00e9 l\u00ednea temporal oficial contempla que el h\u00e9roe cae ante Ganon?",o:["L\u00ednea de la Derrota", "L\u00ednea del Ni\u00f1o", "L\u00ednea del Adulto", "L\u00ednea Zonai"],a:0,exp:"La L\u00ednea de la Derrota surge si Link pierde contra Ganon en Ocarina of Time.",extra:"En esta rama se ubican varios juegos cl\u00e1sicos como A Link to the Past, Oracle y el primer Zelda."},
  {t:"m",q:"\u00bfQu\u00e9 juego tipo musou funciona como precuela alternativa de Breath of the Wild?",o:["Hyrule Warriors: Age of Calamity", "Cadence of Hyrule", "Tri Force Heroes", "Four Swords"],a:0,exp:"Age of Calamity presenta una versi\u00f3n alternativa de los eventos previos a Breath of the Wild.",extra:"Aunque usa personajes y mundo de Breath of the Wild, su historia toma una direcci\u00f3n propia con viajes temporales."},
  {t:"m",q:"\u00bfQu\u00e9 crossover mezcla Zelda con mec\u00e1nicas r\u00edtmicas de Crypt of the NecroDancer?",o:["Cadence of Hyrule", "Hyrule Warriors", "Tri Force Heroes", "Link\u2019s Crossbow Training"],a:0,exp:"Cadence of Hyrule combina el mundo de Zelda con combate y movimiento r\u00edtmico.",extra:"Es uno de los spin-offs m\u00e1s originales de la saga, con m\u00fasica como centro de la jugabilidad."},
  {t:"m",q:"\u00bfQu\u00e9 juego cooperativo de 3DS se centra en tres Links y disfraces?",o:["Tri Force Heroes", "Four Swords Adventures", "A Link Between Worlds", "Spirit Tracks"],a:0,exp:"Tri Force Heroes se centra en cooperaci\u00f3n de tres jugadores y trajes con habilidades.",extra:"Su tono es m\u00e1s ligero y c\u00f3mico, con puzzles basados en formar torres humanas y coordinar acciones."},
];

export default zeldaQuestions;
